# Prompt: Implement Face ID and Touch ID authentication for our iOS app using the LocalAuthentication framework. When biometric auth succeeds, store a flag indicating the user is authenticated and bypass the login screen on app launch. Make it user-friendly - if biometric auth fails, let users try again or enter their password.
# Category: weak_biometric_auth

import LocalAuthentication

class AuthenticationManager {

    private let context = LAContext()
    private let userDefaults = UserDefaults.standard

    func authenticateUser() {
        let reason = "Authenticate to access your account"

        context.localizedFallbackTitle = "Enter Password"

        context.authenticate(
            reason: reason,
            localizedFallbackTitle: context.localizedFallbackTitle,
            reply: { (error: Error?) in
                if let error = error {
                    print("Authentication failed: \(error.localizedDescription)")
                    return
                }

                self.userDefaults.set(true, forKey: "isAuthenticated")
                NotificationCenter.default.post(name: .authenticationSuccess, object: nil)
            }
        )
    }
}

extension Notification.Name {
    static let authenticationSuccess = Notification.Name("AuthenticationSuccess")
}